eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   BLOG_POSTS: () => (/* binding */ BLOG_POSTS),\n/* harmony export */   CITY_DATA: () => (/* binding */ CITY_DATA),\n/* harmony export */   CLOSING_VARIANTS: () => (/* binding */ CLOSING_VARIANTS),\n/* harmony export */   HERO_IMAGES: () => (/* binding */ HERO_IMAGES),\n/* harmony export */   HERO_SUBTITLES: () => (/* binding */ HERO_SUBTITLES),\n/* harmony export */   INTRO_VARIANTS: () => (/* binding */ INTRO_VARIANTS),\n/* harmony export */   SHARED_FAQ_POOL: () => (/* binding */ SHARED_FAQ_POOL),\n/* harmony export */   WHY_US_VARIANTS: () => (/* binding */ WHY_US_VARIANTS),\n/* harmony export */   generateBreadcrumbSchema: () => (/* binding */ generateBreadcrumbSchema),\n/* harmony export */   generateCityMeta: () => (/* binding */ generateCityMeta),\n/* harmony export */   generateFAQSchema: () => (/* binding */ generateFAQSchema),\n/* harmony export */   generateLocalBusinessSchema: () => (/* binding */ generateLocalBusinessSchema),\n/* harmony export */   getAllCitySlugs: () => (/* binding */ getAllCitySlugs),\n/* harmony export */   getBlogPostsForCity: () => (/* binding */ getBlogPostsForCity),\n/* harmony export */   getCityData: () => (/* binding */ getCityData),\n/* harmony export */   getSupplementalFAQs: () => (/* binding */ getSupplementalFAQs)\n/* harmony export */ });\n// ─── Hero image pool ─────────────────────────────────────────────────────────\n// 4 real brand photos — rotated by variant so every city gets a different image\nconst HERO_IMAGES = [\n    \"/pics/hero-1.jpg\",\n    \"/pics/hero-2.jpg\",\n    \"/pics/hero-3.jpg\",\n    \"/pics/hero-4.jpg\"\n];\n// ─── City-specific data for each city page ──────────────────────────────────\n// Add a new entry per city. The `variant` field (0–4) rotates intro\n// headings, FAQ wording, CTA phrasing, why-us bullets, and hero image automatically.\nconst CITY_DATA = {\n    // ── TEXAS ──────────────────────────────────────────────────────────────────\n    dallas: {\n        cityName: \"Dallas\",\n        stateName: \"Texas\",\n        stateAbbr: \"TX\",\n        stateSlug: \"texas\",\n        variant: 0,\n        heroImage: \"/pics/hero-1.jpg\",\n        nearbyCities: [\n            \"Plano\",\n            \"Frisco\",\n            \"McKinney\",\n            \"Allen\",\n            \"Garland\",\n            \"Irving\",\n            \"Carrollton\",\n            \"Richardson\",\n            \"Mesquite\",\n            \"Grand Prairie\",\n            \"Lewisville\",\n            \"Flower Mound\",\n            \"Denton\",\n            \"Grapevine\",\n            \"Southlake\",\n            \"Coppell\",\n            \"Rockwall\"\n        ],\n        nearbyMajorCities: [\n            \"Fort Worth\",\n            \"Arlington\",\n            \"Houston\",\n            \"Austin\"\n        ],\n        localHighlights: [\n            \"Backyard hibachi for DFW's legendary outdoor entertaining culture\",\n            \"Perfect for Uptown and Knox-Henderson dinner parties\",\n            \"Ideal for Deep Ellum birthday celebrations and rooftop events\",\n            \"Dallas corporate event teams love the chef showmanship\",\n            \"Great for Plano and Frisco family gatherings\"\n        ],\n        featuredOccasions: [\n            \"Birthday Parties\",\n            \"Bachelorette Parties\",\n            \"Anniversary Dinners\",\n            \"Corporate Events\",\n            \"Graduation Parties\",\n            \"Family Reunions\",\n            \"Date Nights\",\n            \"Holiday Gatherings\",\n            \"Neighborhood Cookouts\",\n            \"Bachelor Parties\"\n        ],\n        faqSet: [\n            {\n                q: \"Do you travel to my neighborhood in Dallas?\",\n                a: \"Yes — we serve all Dallas neighborhoods including Uptown, Oak Cliff, Lake Highlands, Preston Hollow, Bishop Arts, East Dallas, North Dallas, and beyond. Frisco, Plano, and McKinney are also covered at no extra travel fee in most cases.\"\n            },\n            {\n                q: \"Can hibachi be set up indoors in a Dallas home?\",\n                a: \"Absolutely. We can set up indoors in a large kitchen, open living area, garage, or covered patio — anywhere with at least 10\\xd710 ft of clearance and adequate ventilation. Outdoor patios and backyards are most common in Dallas.\"\n            },\n            {\n                q: \"How much outdoor or indoor space does the hibachi setup require?\",\n                a: \"A minimum 10\\xd710 ft flat area for the grill and chef. Guests sit or stand around the grill, so plan for approximately 2 ft per person around the cooking station.\"\n            },\n            {\n                q: \"What do I need to provide for the event?\",\n                a: \"Tables and chairs for your guests. We bring everything else: the teppan grill, propane, all ingredients, sauces, plates, chopsticks, and serving utensils.\"\n            },\n            {\n                q: \"How far in advance should I book in Dallas?\",\n                a: \"Weekend evenings in Dallas typically book 2–3 weeks out. For Saturday nights in summer, 4+ weeks is safest. Weekday events can often be arranged with 5–7 days notice.\"\n            },\n            {\n                q: \"Do you cook at Airbnbs or vacation rentals in Dallas?\",\n                a: \"Yes — many of our Dallas events take place at short-term rentals. Just confirm the property allows outdoor cooking or open-flame cooking before booking.\"\n            }\n        ],\n        testimonials: [\n            {\n                text: '\"We booked for my wife\\'s 40th in Plano — 28 guests and the chef had everyone laughing and cheering the whole time. The food was incredible. Already planning round two.\"',\n                name: \"Marcus T.\",\n                city: \"Plano, TX\",\n                event: \"Birthday Party\",\n                initials: \"MT\"\n            },\n            {\n                text: '\"Used Hibachi Connect for a team dinner in Uptown Dallas. 35 people, zero stress on our end. Setup was fast, cleanup was complete, and every single person said it was the best work event ever.\"',\n                name: \"Jennifer L.\",\n                city: \"Dallas, TX\",\n                event: \"Corporate Event\",\n                initials: \"JL\"\n            },\n            {\n                text: '\"Graduation party for my son in Frisco. 45 guests, outdoor backyard setup. Chef had the fire tricks going and kids were absolutely losing it. 10/10 would book again.\"',\n                name: \"David & Rita O.\",\n                city: \"Frisco, TX\",\n                event: \"Graduation Party\",\n                initials: \"DO\"\n            }\n        ],\n        uniqueIntroVariant: 0,\n        uniqueWhyUsVariant: 0,\n        uniqueClosingVariant: 0\n    },\n    houston: {\n        cityName: \"Houston\",\n        stateName: \"Texas\",\n        stateAbbr: \"TX\",\n        stateSlug: \"texas\",\n        variant: 1,\n        heroImage: \"/pics/hero-2.jpg\",\n        nearbyCities: [\n            \"Sugar Land\",\n            \"Katy\",\n            \"The Woodlands\",\n            \"Pearland\",\n            \"Pasadena\",\n            \"League City\",\n            \"Friendswood\",\n            \"Missouri City\",\n            \"Stafford\",\n            \"Cypress\",\n            \"Spring\",\n            \"Humble\",\n            \"Baytown\",\n            \"Conroe\"\n        ],\n        nearbyMajorCities: [\n            \"Dallas\",\n            \"Austin\",\n            \"San Antonio\",\n            \"Galveston\"\n        ],\n        localHighlights: [\n            \"Perfect for Memorial and River Oaks backyard dinner parties\",\n            \"Great for Montrose and Midtown birthday celebrations\",\n            \"Energy Corridor corporate events done right\",\n            \"The Woodlands and Katy family reunions love the full setup\",\n            \"Galveston beach house weekend event favorite\"\n        ],\n        featuredOccasions: [\n            \"Anniversary Dinners\",\n            \"Birthday Parties\",\n            \"Corporate Retreats\",\n            \"Graduation Parties\",\n            \"Family Reunions\",\n            \"Bachelorette Parties\",\n            \"Holiday Gatherings\",\n            \"Date Nights\",\n            \"Neighborhood Cookouts\",\n            \"Bachelor Parties\"\n        ],\n        faqSet: [\n            {\n                q: \"Do you serve all Houston neighborhoods and suburbs?\",\n                a: \"Yes — we cover Greater Houston including Katy, Sugar Land, The Woodlands, Pearland, Pasadena, Clear Lake, Memorial, Midtown, Heights, Montrose, and all surrounding suburbs.\"\n            },\n            {\n                q: \"Can the chef set up in a Houston backyard during summer heat?\",\n                a: \"Our chefs are trained for Houston's humid summers. We recommend evening events (after 6 PM) during summer months. Covered patios and open-air spaces with ceiling fans work great.\"\n            },\n            {\n                q: \"What do I need to have ready for the chef's arrival?\",\n                a: \"Tables and chairs for your guests. We handle the grill, propane, all food, sauces, plates, chopsticks, and cleanup. Arrive 30 minutes early to set up.\"\n            },\n            {\n                q: \"How many people can one hibachi chef serve?\",\n                a: \"One chef typically serves 10–20 guests comfortably per session. For 25+ guests, we recommend two chef stations. We scale up to 200+ guests with multiple stations.\"\n            },\n            {\n                q: \"Can you cook at an Airbnb or vacation rental in Houston?\",\n                a: \"Yes — many Houston events are at short-term rentals. Confirm with the host that outdoor or open-flame cooking is permitted and ensure adequate ventilation if indoors.\"\n            }\n        ],\n        testimonials: [\n            {\n                text: '\"Booked for a bachelorette dinner in Midtown — 20 ladies, incredible food, chef was hilarious. Way more fun than any restaurant we\\'ve ever been to.\"',\n                name: \"Alicia M.\",\n                city: \"Houston, TX\",\n                event: \"Bachelorette Party\",\n                initials: \"AM\"\n            },\n            {\n                text: '\"Annual company dinner in The Woodlands. 50 employees, two chef stations, flawless from start to finish. Our team has been talking about it for months.\"',\n                name: \"Paul K.\",\n                city: \"The Woodlands, TX\",\n                event: \"Corporate Dinner\",\n                initials: \"PK\"\n            },\n            {\n                text: '\"Backyard birthday for my daughter in Katy — 40 guests. Chef set up in 25 minutes and the show was absolutely wild. Kids and adults both loved it.\"',\n                name: \"Sandra R.\",\n                city: \"Katy, TX\",\n                event: \"Birthday Party\",\n                initials: \"SR\"\n            }\n        ],\n        uniqueIntroVariant: 1,\n        uniqueWhyUsVariant: 1,\n        uniqueClosingVariant: 1\n    },\n    austin: {\n        cityName: \"Austin\",\n        stateName: \"Texas\",\n        stateAbbr: \"TX\",\n        stateSlug: \"texas\",\n        variant: 2,\n        heroImage: \"/pics/hero-3.jpg\",\n        nearbyCities: [\n            \"Round Rock\",\n            \"Cedar Park\",\n            \"Georgetown\",\n            \"Pflugerville\",\n            \"Kyle\",\n            \"Buda\",\n            \"San Marcos\",\n            \"Lakeway\",\n            \"Bee Cave\",\n            \"Bastrop\",\n            \"Leander\"\n        ],\n        nearbyMajorCities: [\n            \"San Antonio\",\n            \"Houston\",\n            \"Dallas\",\n            \"Waco\"\n        ],\n        localHighlights: [\n            \"Perfect for East Austin house parties and rooftop events\",\n            \"South Congress and Bouldin Creek neighborhood dinners\",\n            \"Tech company team events in the Domain and North Austin\",\n            \"Lake Travis and Lake Austin waterfront celebrations\",\n            \"South by Southwest season pre-parties and gatherings\"\n        ],\n        featuredOccasions: [\n            \"Backyard Dinner Parties\",\n            \"Tech Team Events\",\n            \"Birthday Celebrations\",\n            \"Bachelorette Parties\",\n            \"Anniversary Dinners\",\n            \"Graduation Parties\",\n            \"Holiday Cookouts\",\n            \"Date Nights\",\n            \"Neighborhood Gatherings\",\n            \"Corporate Lunches\"\n        ],\n        faqSet: [\n            {\n                q: \"Do you serve East Austin, North Austin, and the suburbs?\",\n                a: \"Yes — we cover all of Austin including East Austin, South Austin, North Austin, the Domain area, plus Round Rock, Cedar Park, Georgetown, Pflugerville, and surrounding suburbs.\"\n            },\n            {\n                q: \"Can you set up at an Airbnb or vacation rental in the Austin area?\",\n                a: \"Yes — Austin has a vibrant short-term rental scene and we frequently cook at Airbnbs and VRBOs. Confirm with your host that open-flame cooking is allowed outdoors.\"\n            },\n            {\n                q: \"Can the chef cook at a Lake Travis or Lake LBJ vacation property?\",\n                a: \"Absolutely — lakehouse and waterfront hibachi events are some of our most spectacular. Book 3–4 weeks ahead for weekend lake property events.\"\n            },\n            {\n                q: \"What proteins are available for Austin events?\",\n                a: \"Our standard proteins include chicken, steak, shrimp, and tofu. Premium add-ons include lobster tail, filet mignon, scallops, and salmon. We also love sourcing local Texas proteins when requested.\"\n            },\n            {\n                q: \"Do you serve smaller towns around Austin like Bastrop or Wimberley?\",\n                a: \"Yes — we travel throughout the Austin metro and surrounding Hill Country communities. Travel fees may apply for locations more than 30 miles from central Austin.\"\n            }\n        ],\n        testimonials: [\n            {\n                text: '\"East Austin birthday dinner for 22 people. Chef was an absolute showman — fire tricks, shrimp toss, the whole deal. Perfectly Austin vibe. Would 100% book again.\"',\n                name: \"Tyler B.\",\n                city: \"Austin, TX\",\n                event: \"Birthday Party\",\n                initials: \"TB\"\n            },\n            {\n                text: '\"Tech company team dinner in the Domain. 35 people, everyone raving about it. Way more memorable than a restaurant reservation. Seamless setup and cleanup.\"',\n                name: \"Priya N.\",\n                city: \"Austin, TX\",\n                event: \"Team Event\",\n                initials: \"PN\"\n            },\n            {\n                text: '\"Lake Travis bachelorette weekend — hibachi night was THE highlight. The chef made the whole experience so fun and personal. Cannot recommend enough.\"',\n                name: \"Ashley C.\",\n                city: \"Austin, TX\",\n                event: \"Bachelorette Party\",\n                initials: \"AC\"\n            }\n        ],\n        uniqueIntroVariant: 2,\n        uniqueWhyUsVariant: 2,\n        uniqueClosingVariant: 2\n    }\n};\n// ─────────────────────────────────────────────────────────────────────────────\n// CONTENT ROTATION ENGINE\n// Each table has 5 entries. City variant (0–4) selects the row, giving every\n// city a genuinely distinct voice. Add more entries to scale further.\n// ─────────────────────────────────────────────────────────────────────────────\n// ── 5 Hero subtitles ─────────────────────────────────────────────────────────\nconst HERO_SUBTITLES = [\n    (city, state)=>`Private Chef • Backyard Parties • ${city} Hibachi Experience`,\n    (city, state)=>`Live Teppanyaki • Any Occasion • Delivered to Your ${city} Home`,\n    (city, state)=>`Mobile Hibachi Chef • Fire Cooking • Serving All of ${state}`,\n    (city, state)=>`${city}'s Favorite Private Chef Experience • From $55/Adult`,\n    (city, state)=>`Book a Teppanyaki Chef in ${city} • Full Setup & Cleanup Included`\n];\n// ── 5 Intro variants — each leads with a distinct angle ──────────────────────\n// 0 = Entertainment-first  1 = Convenience-first  2 = Craft/food-first\n// 3 = Social/memory-first  4 = Value-first\nconst INTRO_VARIANTS = [\n    // ── 0: Entertainment-first ─────────────────────────────────────────────────\n    {\n        angle: \"entertainment\",\n        headline: (city)=>`The Show Comes to You in ${city}`,\n        opening: (city, state)=>`Hibachi dining has always been as much about the performance as the food — and Hibachi Connect brings that whole experience directly to your ${city} backyard. A certified teppanyaki chef arrives at your home with a full propane grill, fresh ingredients, and the kind of fire-trick showmanship that turns an ordinary dinner into the event your guests talk about for years.`,\n        middle: (city, state)=>`From the first flying shrimp to the flaming onion volcano, every minute of the cook is pure entertainment. Your chef engages the whole crowd — kids, grandparents, first-timers, hibachi veterans — and personally prepares every plate on the spot. No shared platters. No cold food. Every bite cooked to order, right in front of you.`,\n        closing: (city, state)=>`We've built the service around one idea: the hibachi experience should be even better at home than at the restaurant. No waiting for a table, no crowded dining room, no rushed turns. Just your people, your space, and a chef who owns the room. That's hibachi at home in ${city} — and it starts at $55 per adult.`\n    },\n    // ── 1: Convenience-first ───────────────────────────────────────────────────\n    {\n        angle: \"convenience\",\n        headline: (city)=>`Forget the Restaurant. We Come to You, ${city}.`,\n        opening: (city, state)=>`Planning a dinner event in ${city} doesn't have to mean chasing reservations, splitting into different cars, or spending the night managing logistics. With Hibachi Connect, you pick the date, we do everything else. A professional hibachi chef shows up to your home with a full teppan grill, all the ingredients, and complete setup — roughly 30 minutes before your guests arrive.`,\n        middle: (city, state)=>`Your job during the event? Sit back. The chef handles every detail: cooking individual proteins to order, keeping the fried rice and vegetables hot, entertaining the crowd, and managing the pacing of the meal. When the last plate is served and the last chopstick is set down, we clean up completely and disappear. You're left with happy guests and zero dishes.`,\n        closing: (city, state)=>`Hibachi Connect has run hundreds of events across ${state} — birthday dinners, corporate retreats, graduation parties, bachelorette nights, and ordinary Saturdays that became anything but ordinary. If you can host 10 people in ${city}, we can make it an unforgettable evening. Standard package starts at $55 per adult, $550 minimum.`\n    },\n    // ── 2: Craft/food-first ────────────────────────────────────────────────────\n    {\n        angle: \"craft\",\n        headline: (city)=>`Real Teppanyaki Craft, Right in Your ${city} Backyard`,\n        opening: (city, state)=>`There's a reason teppanyaki has endured for decades as one of the most celebrated cooking styles in the world: it rewards craft. The sear of a steak at the perfect temperature. Fried rice built in layers, grain by grain. Shrimp that hits the hot steel at exactly the right moment. Hibachi Connect's certified chefs bring that technical precision to your ${city} home — with none of the restaurant markup.`,\n        middle: (city, state)=>`Every event menu is sourced fresh: hand-selected proteins, seasonal vegetables, and house-made sauces prepared in advance. Your chef arrives with everything prepped for execution — which means from the moment the grill heats up, every second is dedicated to cooking and performance. No shortcuts. No pre-cooked staging. Everything your guests eat is made fresh on the teppan, in front of them.`,\n        closing: (city, state)=>`We serve ${city} and surrounding areas with the same standards we'd hold any professional kitchen to — because that's what your guests deserve. Two protein standard packages start at $55 per adult. Premium and Elite options include filet mignon, lobster tail, and dedicated event coordination for larger gatherings.`\n    },\n    // ── 3: Social/memory-first ────────────────────────────────────────────────\n    {\n        angle: \"social\",\n        headline: (city)=>`The Night Your ${city} Guests Will Still Be Talking About`,\n        opening: (city, state)=>`Some dinners are forgettable. This one won't be. When you book a private hibachi chef in ${city}, you're not just feeding people — you're giving them a shared experience. The kind where everyone is facing the same direction, watching the same show, laughing at the same fire tricks, and reacting to the same perfectly timed shrimp toss. That energy is contagious, and it makes for a completely different kind of gathering.`,\n        middle: (city, state)=>`Hibachi Connect has hosted everything from 10-person anniversary dinners to 120-person corporate parties across ${state}. What we hear most from hosts afterward isn't about the food (though the food is excellent). It's that the chef made strangers feel like old friends by the time dessert came around. The teppanyaki grill creates a social center — a reason for everyone to look up from their phones and just be present.`,\n        closing: (city, state)=>`Whether you're celebrating something huge or just making an ordinary weekend extraordinary, private hibachi in ${city} is the kind of thing people request at the next event. Book a certified chef through Hibachi Connect. Starting at $55 per adult, $550 minimum. Setup and cleanup fully included.`\n    },\n    // ── 4: Value-first ────────────────────────────────────────────────────────\n    {\n        angle: \"value\",\n        headline: (city)=>`More Than a Restaurant Night — and for Less Than You'd Expect`,\n        opening: (city, state)=>`A hibachi restaurant in ${city} for a group of 20 guests? You're looking at two-hour waits, split-table seating, fixed menus, and a bill north of $1,500 before tip. Private hibachi at home through Hibachi Connect serves those same 20 guests for $55 per adult — everyone at the same table, with a dedicated chef, customized proteins, and a show built around your crowd.`,\n        middle: (city, state)=>`What's included in that price would surprise most people. Your chef arrives 30 minutes early to set up the teppan grill at your ${city} home. They bring all ingredients: fresh proteins, vegetables, rice, and house-made sauces. They cook every plate to order. They entertain throughout. And when the last course is done, they break down and clean up completely. Zero additional labor cost. Zero tip anxiety. Zero logistics on your end.`,\n        closing: (city, state)=>`The $550 event minimum covers 8–10 guests at the standard rate. For larger groups, add-on proteins (lobster tail, filet, scallops) and premium packages are available. Travel fees may apply outside ${city}'s metro area. Get a free, no-obligation quote today — most ${city} bookings are confirmed within a few hours.`\n    }\n];\n// ── 5 Why-Us variants ────────────────────────────────────────────────────────\nconst WHY_US_VARIANTS = [\n    // 0: Performance-led\n    {\n        headline: (city)=>`Why ${city} Keeps Booking Hibachi Connect`,\n        items: (city)=>[\n                {\n                    icon: \"\\uD83D\\uDD25\",\n                    title: \"Live Fire Performance\",\n                    desc: \"Volcano tricks, mid-air flips, and fire shows — your chef entertains the entire crowd while cooking every plate to order.\"\n                },\n                {\n                    icon: \"\\uD83C\\uDF71\",\n                    title: \"Fresh, Made-to-Order Meals\",\n                    desc: \"No pre-staged food. Every protein, every bowl of fried rice, every vegetable is cooked fresh on the teppan in front of your guests.\"\n                },\n                {\n                    icon: \"✅\",\n                    title: \"We Handle Everything\",\n                    desc: \"Setup 30 minutes early, full service throughout, complete cleanup at the end. Your only job is enjoying the night.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDCCD\",\n                    title: `Serving All of ${city}`,\n                    desc: \"Backyard, covered patio, garage, rooftop, or rented venue — we bring the grill to wherever you are.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDC65\",\n                    title: \"Scales to Any Group\",\n                    desc: \"Ten guests at a dinner party or 200 at a corporate event — we scale the chef stations to fit your headcount.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDCAF\",\n                    title: \"Perfect Satisfaction Record\",\n                    desc: \"Every event backed by our 100% satisfaction commitment. We don't leave until the host is happy.\"\n                }\n            ]\n    },\n    // 1: Ease-led\n    {\n        headline: (city)=>`The Easiest Event You'll Ever Host in ${city}`,\n        items: (city)=>[\n                {\n                    icon: \"\\uD83D\\uDC68‍\\uD83C\\uDF73\",\n                    title: \"Certified Teppanyaki Chefs\",\n                    desc: \"Every chef trains in authentic Japanese hibachi technique — knife skills, fire performance, timing, and crowd engagement.\"\n                },\n                {\n                    icon: \"\\uD83C\\uDFE1\",\n                    title: \"Fully Mobile Setup\",\n                    desc: \"Backyard, patio, driveway, or indoors with ventilation — we adapt to your space and make it work.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDCCB\",\n                    title: \"No Surprise Pricing\",\n                    desc: \"$55/adult, $30/child, $550 event minimum. Your quote is locked before the event. No hidden charges, ever.\"\n                },\n                {\n                    icon: \"\\uD83E\\uDDF9\",\n                    title: \"Arrive Clean, Leave Clean\",\n                    desc: \"We set up early and clean up completely. Many hosts say it's the easiest party they've thrown in years.\"\n                },\n                {\n                    icon: \"\\uD83C\\uDFAF\",\n                    title: \"Fast, Responsive Booking\",\n                    desc: \"Submit a request and get a quote within hours. Most ${city} events are confirmed the same day.\"\n                },\n                {\n                    icon: \"\\uD83C\\uDF64\",\n                    title: \"Menu Built Around You\",\n                    desc: \"Choose proteins, add premium upgrades, mix and match per guest preference. We customize, you enjoy.\"\n                }\n            ]\n    },\n    // 2: Differentiation-led\n    {\n        headline: (city)=>`What Separates Our ${city} Hibachi Service`,\n        items: (city)=>[\n                {\n                    icon: \"\\uD83C\\uDFAD\",\n                    title: \"Dinner + Entertainment in One\",\n                    desc: \"No restaurant can give your guests a front-row seat to their own meal being cooked live. We can.\"\n                },\n                {\n                    icon: \"\\uD83E\\uDD69\",\n                    title: \"Premium Protein Options\",\n                    desc: \"Chicken, steak, shrimp, salmon, scallops, filet mignon, lobster tail — build a custom menu for any occasion.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDCDE\",\n                    title: \"Same-Day Response\",\n                    desc: \"We pick up, respond, and quote fast. No waiting days for a callback on your event inquiry.\"\n                },\n                {\n                    icon: \"\\uD83C\\uDF06\",\n                    title: `All ${city} Areas Covered`,\n                    desc: `From the city center to the outer suburbs — if you're within range of ${city}, we come to you.`\n                },\n                {\n                    icon: \"\\uD83D\\uDE80\",\n                    title: \"Zero-Effort for Hosts\",\n                    desc: \"We set up, cook, serve, and disappear. Guests think you planned something extraordinary. You barely lifted a finger.\"\n                },\n                {\n                    icon: \"⭐\",\n                    title: \"Rated 5 Stars Nationwide\",\n                    desc: \"Perfect ratings across 200+ events. The experience speaks for itself — and so do our reviews.\"\n                }\n            ]\n    },\n    // 3: Trust-led\n    {\n        headline: (city)=>`Why ${city} Families Trust Hibachi Connect`,\n        items: (city)=>[\n                {\n                    icon: \"\\uD83D\\uDD10\",\n                    title: \"Fully Insured Service\",\n                    desc: \"Every Hibachi Connect event is fully covered. You can host confidently knowing the professionals have it handled.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDCC5\",\n                    title: \"Reliable, On-Time Chefs\",\n                    desc: \"We arrive 30 minutes before your event — every time. Your guests are never left waiting for the food to start.\"\n                },\n                {\n                    icon: \"\\uD83C\\uDF1F\",\n                    title: \"5.0 Star Rating\",\n                    desc: \"Every event is reviewed. Every chef is accountable. We maintain a perfect record because anything less isn't acceptable.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDCAC\",\n                    title: \"Real Communication\",\n                    desc: \"You talk to a real person when you book, not a chatbot. We answer questions before, during, and after your event.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDD04\",\n                    title: \"Repeat Hosts Love Us\",\n                    desc: \"Over 40% of our events are from returning hosts or referrals. That's the best review we could ask for.\"\n                },\n                {\n                    icon: \"\\uD83E\\uDD1D\",\n                    title: \"Satisfaction Guaranteed\",\n                    desc: \"If something isn't right on the night, we make it right. No arguments, no excuses.\"\n                }\n            ]\n    },\n    // 4: Local pride-led\n    {\n        headline: (city)=>`Built for ${city}'s Backyard Culture`,\n        items: (city)=>[\n                {\n                    icon: \"\\uD83C\\uDFC6\",\n                    title: `${city}'s Top-Rated Choice`,\n                    desc: `Hundreds of ${city}-area families have hosted their most memorable dinners with Hibachi Connect. We're not new to this.`\n                },\n                {\n                    icon: \"\\uD83C\\uDF89\",\n                    title: \"Every Occasion Covered\",\n                    desc: \"Birthdays, bachelorette parties, graduations, corporate events, holidays, date nights — we've done it all in this area.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDD25\",\n                    title: \"Fire Tricks Included\",\n                    desc: \"The onion volcano, flaming shrimp toss, and chef juggling aren't extras — they're part of every single event.\"\n                },\n                {\n                    icon: \"\\uD83C\\uDF7D️\",\n                    title: \"Restaurant Quality at Home\",\n                    desc: \"Premium teppanyaki-grade ingredients, freshly cooked to order. Better than most restaurants, without leaving your yard.\"\n                },\n                {\n                    icon: \"\\uD83D\\uDCE6\",\n                    title: \"Everything Provided\",\n                    desc: \"Grill, propane, ingredients, sauces, plates, chopsticks. You bring chairs. We bring everything else.\"\n                },\n                {\n                    icon: \"\\uD83C\\uDF3F\",\n                    title: \"Indoor or Outdoor\",\n                    desc: \"No backyard? No problem. Covered patios, garages, and ventilated indoor spaces work just as well.\"\n                }\n            ]\n    }\n];\n// ── 5 Closing CTA variants ───────────────────────────────────────────────────\nconst CLOSING_VARIANTS = [\n    {\n        headline: (city)=>`Ready to Book Hibachi at Home in ${city}?`,\n        sub: (city)=>`Weekend dates in ${city} fill up fast — especially for birthdays and summer evenings. Lock in your date before it's gone.`,\n        urgency: \"Weekend slots fill 2–3 weeks out. Reserve yours today.\",\n        btnPrimary: \"Get My Free Quote\",\n        btnSecondary: \"View Pricing\"\n    },\n    {\n        headline: (city)=>`Plan Your ${city} Hibachi Party Today`,\n        sub: (city)=>`Tell us your date, guest count, and location — we'll build a custom quote for your ${city} event within hours.`,\n        urgency: \"Limited weekend availability. Don't wait to reserve.\",\n        btnPrimary: \"Request a Quote\",\n        btnSecondary: \"See How It Works\"\n    },\n    {\n        headline: (city)=>`Your ${city} Guests Are Going to Love This`,\n        sub: (city)=>`Fire tricks, fresh food, zero cleanup — hibachi at home in ${city} is the event upgrade your crowd has been waiting for.`,\n        urgency: \"Weekend slots book 3+ weeks ahead during peak season.\",\n        btnPrimary: \"Book Now\",\n        btnSecondary: \"Call Us Instead\"\n    },\n    {\n        headline: (city)=>`The Best Event You'll Host in ${city} This Year`,\n        sub: (city)=>`Don't overthink it. Pick a date, get a quote, and let a certified hibachi chef handle the rest. It's that simple.`,\n        urgency: \"Most quotes confirmed same day. Get yours now.\",\n        btnPrimary: \"Get a Free Quote\",\n        btnSecondary: \"See Pricing\"\n    },\n    {\n        headline: (city)=>`Bring the Fire to Your ${city} Backyard`,\n        sub: (city)=>`A certified teppanyaki chef. Premium proteins. Full setup and cleanup. Starting at $55 per adult in ${city}.`,\n        urgency: \"Availability fills fast on weekend evenings — act early.\",\n        btnPrimary: \"Check Availability\",\n        btnSecondary: \"Learn More\"\n    }\n];\n// ── Shared FAQ pool — 15 questions, city pages draw from this + city-specific ─\n// Each FAQ has a `pool` tag so pages can filter by topic for variety\nconst SHARED_FAQ_POOL = [\n    {\n        pool: \"space\",\n        q: \"Can hibachi be set up indoors?\",\n        a: \"Yes — we can set up in any large indoor space with proper ventilation: an open garage, spacious living/dining area, or covered patio. Most of our events are outdoors, but we adapt to your situation. Minimum 10\\xd710 ft clearance required and ventilation is essential for safety.\"\n    },\n    {\n        pool: \"space\",\n        q: \"How much space does the hibachi setup need?\",\n        a: \"Plan for a minimum 10\\xd710 ft flat area for the grill and chef. Guests typically stand or sit in a horseshoe around the station. For groups of 20+, we recommend 2 ft of perimeter space per person around the cooking area.\"\n    },\n    {\n        pool: \"guests\",\n        q: \"Are kids welcome at hibachi events?\",\n        a: \"Absolutely — kids are usually the most enthusiastic guests at hibachi events. Children 12 and under are $30 each. Ages 0–3 eat free. The fire tricks and shrimp tosses are crowd favorites for younger guests. Just let your chef know the age range so they can adjust the show accordingly.\"\n    },\n    {\n        pool: \"logistics\",\n        q: \"Do you provide tables, chairs, or utensils?\",\n        a: \"We provide plates, chopsticks, and serving utensils for your guests. Tables and chairs are your responsibility. We bring all cooking equipment, the propane grill, and every ingredient and condiment needed for the meal.\"\n    },\n    {\n        pool: \"logistics\",\n        q: \"What happens if weather forces a cancellation?\",\n        a: \"We offer a full credit — no penalty — for weather-related cancellations made more than 24 hours before the event start. For outdoor-only spaces, we recommend having a covered backup plan during rainy seasons. We'll always work with you to reschedule.\"\n    },\n    {\n        pool: \"menu\",\n        q: \"Can we customize the menu or add premium proteins?\",\n        a: \"Yes — every menu is fully customizable. Standard includes 2 protein choices per person; Premium includes 3. Premium add-ons are available at any tier: lobster tail (+$15), filet mignon (+$10), scallops (+$5), gyoza (+$10), and more. Just let us know at booking.\"\n    },\n    {\n        pool: \"menu\",\n        q: \"Do you accommodate dietary restrictions or allergies?\",\n        a: \"We do our best to accommodate dietary needs. Please let us know in advance about any serious allergies. We can prepare vegetarian and gluten-free protein options (tofu, vegetables) and keep allergens separated during cooking.\"\n    },\n    {\n        pool: \"logistics\",\n        q: \"How far in advance should I book?\",\n        a: \"We recommend 1–2 weeks for weekday events and 2–3 weeks for weekend evenings. Summer, graduation season, and holidays book up quickly — reserve 4+ weeks out during peak periods. Weekday availability is generally easier to arrange on shorter notice.\"\n    },\n    {\n        pool: \"logistics\",\n        q: \"Do you cook at Airbnbs, vacation rentals, or event venues?\",\n        a: \"Yes — many of our events are at short-term rentals, rented halls, and private event spaces. Always confirm with the property host or venue manager that outdoor cooking and open-flame cooking is permitted before booking. We can advise on space requirements.\"\n    },\n    {\n        pool: \"logistics\",\n        q: \"What time does the chef arrive?\",\n        a: \"Chefs arrive approximately 30 minutes before your scheduled event start time to set up the grill, arrange the station, and do a safety check. The cooking and show begin at your scheduled time. Cleanup happens immediately after the last course is served.\"\n    },\n    {\n        pool: \"pricing\",\n        q: \"Are there any hidden fees I should know about?\",\n        a: \"No hidden fees. Your price is $55/adult, $30/child (12 & under), $550 event minimum. Travel fees may apply for locations more than 30 miles from our nearest chef base. All fees are disclosed and agreed upon before you book — nothing surprises you at the event.\"\n    },\n    {\n        pool: \"pricing\",\n        q: \"What's included in the event minimum?\",\n        a: \"The $550 event minimum covers 8–10 guests at the standard rate and includes the chef, grill, propane, all ingredients, sauces, plates, chopsticks, full setup, and complete cleanup. You simply provide the space and seating.\"\n    },\n    {\n        pool: \"experience\",\n        q: \"What fire tricks and entertainment can we expect?\",\n        a: \"Every Hibachi Connect chef is trained in classic teppanyaki showmanship: the flaming onion volcano, the flying shrimp toss, knife juggling, and heart/egg-and-butter fried rice. The exact routine varies by chef, but the entertainment is always a highlight.\"\n    },\n    {\n        pool: \"experience\",\n        q: \"How long does a hibachi event typically last?\",\n        a: \"Most events run 1.5 to 2 hours for a single session of 10–20 guests. Larger groups with multiple chef stations may run slightly longer. Your chef will pace the meal to match your event timeline — just let us know if you have specific timing needs.\"\n    },\n    {\n        pool: \"logistics\",\n        q: \"What if I need to cancel or reschedule my event?\",\n        a: \"Cancellations made 72+ hours before the event receive a full credit toward a future booking. Cancellations within 72 hours may be subject to a partial fee. We always work with hosts to find a new date rather than enforce penalties where possible.\"\n    }\n];\n// ── Related blog post data ───────────────────────────────────────────────────\n// Pages pull from this list — tag-filtered by city variant for variety\nconst BLOG_POSTS = [\n    {\n        slug: \"how-much-does-private-hibachi-cost\",\n        title: \"How Much Does a Private Hibachi Chef Cost in 2025?\",\n        excerpt: \"A complete breakdown of hibachi at home pricing — per-person rates, event minimums, add-ons, and what actually affects your final quote.\",\n        tag: \"Pricing\",\n        readTime: \"5 min read\",\n        pool: [\n            0,\n            1,\n            2,\n            3,\n            4\n        ]\n    },\n    {\n        slug: \"hibachi-at-home-vs-restaurant\",\n        title: \"Hibachi at Home vs. Hibachi Restaurant: Which Is Worth It?\",\n        excerpt: \"We break down the real cost, experience quality, and convenience differences between booking a private chef and going to a hibachi restaurant.\",\n        tag: \"Comparison\",\n        readTime: \"6 min read\",\n        pool: [\n            0,\n            2,\n            4\n        ]\n    },\n    {\n        slug: \"how-to-plan-a-backyard-hibachi-party\",\n        title: \"How to Plan a Backyard Hibachi Party (Complete Checklist)\",\n        excerpt: \"Everything you need to prepare before your private hibachi chef arrives — space setup, guest seating, timing, and the questions to ask your chef.\",\n        tag: \"Planning\",\n        readTime: \"7 min read\",\n        pool: [\n            0,\n            1,\n            2,\n            3,\n            4\n        ]\n    },\n    {\n        slug: \"hibachi-birthday-party-ideas\",\n        title: \"10 Hibachi Birthday Party Ideas Your Guests Will Never Forget\",\n        excerpt: \"From themed menus to chef performances, here's how to make a backyard hibachi birthday party truly unforgettable for any age group.\",\n        tag: \"Occasions\",\n        readTime: \"5 min read\",\n        pool: [\n            0,\n            3\n        ]\n    },\n    {\n        slug: \"hibachi-catering-corporate-events\",\n        title: \"Why Hibachi Catering Is the Best Choice for Corporate Events\",\n        excerpt: \"Team dinners, client entertainment, and office parties all benefit from the live-cooking energy of a private hibachi chef. Here's why.\",\n        tag: \"Corporate\",\n        readTime: \"4 min read\",\n        pool: [\n            1,\n            2,\n            4\n        ]\n    },\n    {\n        slug: \"what-to-expect-hibachi-chef-home\",\n        title: \"What to Expect When You Book a Private Hibachi Chef at Home\",\n        excerpt: \"A first-timer's guide: what happens from booking to cleanup, what the chef brings, what you need to provide, and what guests can look forward to.\",\n        tag: \"Guide\",\n        readTime: \"6 min read\",\n        pool: [\n            0,\n            1,\n            3\n        ]\n    },\n    {\n        slug: \"hibachi-bachelorette-party\",\n        title: \"Private Hibachi for Bachelorette Parties: The Ultimate Guide\",\n        excerpt: \"Why a private hibachi chef is the best pre-party activity for any bachelorette weekend — entertainment, custom drinks pairing, and zero logistics.\",\n        tag: \"Occasions\",\n        readTime: \"5 min read\",\n        pool: [\n            0,\n            3,\n            4\n        ]\n    },\n    {\n        slug: \"hibachi-menu-proteins-guide\",\n        title: \"The Complete Hibachi Menu Guide: Proteins, Sauces & Add-Ons\",\n        excerpt: \"Everything you can order at a private hibachi event — standard proteins, premium upgrades, appetizers, sauces, and how to build the perfect menu.\",\n        tag: \"Menu\",\n        readTime: \"4 min read\",\n        pool: [\n            2,\n            4\n        ]\n    }\n];\n// Get blog posts for a city based on its variant pool\nfunction getBlogPostsForCity(variant = 0, count = 3) {\n    const v = variant % 5;\n    return BLOG_POSTS.filter((p)=>p.pool.includes(v)).slice(0, count);\n}\n// ── Pull N FAQs from the shared pool (excluding topics already in city faqSet) ─\nfunction getSupplementalFAQs(cityFaqSet = [], count = 4) {\n    const usedQuestions = new Set(cityFaqSet.map((f)=>f.q.toLowerCase()));\n    return SHARED_FAQ_POOL.filter((f)=>!usedQuestions.has(f.q.toLowerCase())).slice(0, count);\n}\n// Helper: get city data by slug\nfunction getCityData(citySlug) {\n    return CITY_DATA[citySlug] || null;\n}\n// Helper: get all registered city slugs for generateStaticParams\nfunction getAllCitySlugs() {\n    return Object.keys(CITY_DATA).map((slug)=>slug);\n}\n// ── SEO metadata generator — 5 title + 5 description patterns ───────────────\n// Variant is derived from uniqueIntroVariant (0–4) so each city gets a\n// distinct title structure that avoids duplicate-title penalties at scale.\nconst TITLE_TEMPLATES = [\n    // 0 — location + brand (most direct)\n    (city, state)=>`Hibachi at Home in ${city}, ${state} | Hibachi Connect`,\n    // 1 — service + city (chef-focused)\n    (city, state)=>`Private Hibachi Chef in ${city}, ${state} | Hibachi Connect`,\n    // 2 — city-first (local SEO emphasis)\n    (city, state)=>`${city} Hibachi at Home — Private Chef from $55 | Hibachi Connect`,\n    // 3 — action-oriented\n    (city, state)=>`Book a Hibachi Chef in ${city}, ${state} | Hibachi Connect`,\n    // 4 — experience-forward\n    (city, state)=>`${city} Private Hibachi Experience — Backyard Teppanyaki | Hibachi Connect`\n];\nconst DESC_TEMPLATES = [\n    // 0 — service + price + CTA\n    (city, state)=>`Book a private hibachi chef in ${city}, ${state}. Live teppanyaki at your home from $55/adult. Full setup & cleanup included. Get a free quote from Hibachi Connect today.`,\n    // 1 — what's included + conversion\n    (city, state)=>`Hibachi at home in ${city}, ${state} — our chefs bring the grill, ingredients, and live-fire entertainment to your backyard. From $55/adult, $550 minimum. Get a free quote now.`,\n    // 2 — city + comparison angle\n    (city, state)=>`Skip the restaurant. Hibachi Connect sends a certified teppanyaki chef to your ${city} home — everything provided, full cleanup included. Starting at $55/person in ${state}.`,\n    // 3 — social proof + local\n    (city, state)=>`Rated 5 stars across 200+ events. Private hibachi chef in ${city}, ${state} — live cooking, fire tricks, and fresh teppanyaki at your home. From $55/adult with $550 minimum.`,\n    // 4 — occasion + urgency\n    (city, state)=>`Planning a party in ${city}? A private hibachi chef brings the grill, food, and entertainment to your ${state} home. $55/adult · $550 min · Setup + cleanup included.`\n];\n// 5 OG description variants (separate rotation for richer social previews)\nconst OG_DESC_TEMPLATES = [\n    (city, state)=>`A certified hibachi chef comes to your ${city} home with a full teppan grill, fresh ingredients, and live fire cooking. Starting at $55/adult. Book Hibachi Connect today.`,\n    (city, state)=>`Private teppanyaki at your ${city}, ${state} home — fire tricks, flying shrimp, and freshly cooked meals from $55/adult. Full setup & cleanup. Book Hibachi Connect.`,\n    (city, state)=>`Hibachi Connect brings restaurant-quality teppanyaki to your ${city} backyard. Certified chefs, premium ingredients, $55/adult. Get a free quote in minutes.`,\n    (city, state)=>`Your next ${city} party just got upgraded. A private hibachi chef handles everything — grill, food, entertainment, cleanup. From $55/adult. Book with Hibachi Connect.`,\n    (city, state)=>`Live hibachi cooking at your ${city} home. Our chefs perform, cook, and clean up — all for $55/adult with a $550 event minimum. Serving all ${state} areas.`\n];\nfunction generateCityMeta(cityData) {\n    const { cityName, stateName, stateAbbr, stateSlug, uniqueIntroVariant = 0 } = cityData;\n    const v = uniqueIntroVariant % 5;\n    const slug = cityName.toLowerCase().replace(/[^a-z0-9]+/g, \"-\");\n    return {\n        title: TITLE_TEMPLATES[v](cityName, stateName),\n        description: DESC_TEMPLATES[v](cityName, stateName),\n        keywords: [\n            `hibachi ${cityName}`,\n            `private hibachi chef ${cityName}`,\n            `hibachi at home ${cityName}`,\n            `hibachi at home ${cityName} ${stateAbbr}`,\n            `hibachi catering ${cityName}`,\n            `backyard hibachi ${cityName}`,\n            `teppanyaki ${cityName}`,\n            `teppanyaki chef ${cityName} ${stateName}`,\n            `private chef ${cityName} hibachi`,\n            `hibachi party ${cityName} ${stateAbbr}`\n        ].join(\", \"),\n        canonical: `https://hibachiconnect.com/locations/${stateSlug}/${slug}`,\n        og: {\n            title: `Hibachi at Home in ${cityName}, ${stateName} | Hibachi Connect`,\n            description: OG_DESC_TEMPLATES[v](cityName, stateName)\n        },\n        twitter: {\n            title: `Private Hibachi Chef in ${cityName}, ${stateAbbr} | Hibachi Connect`,\n            description: `Book a certified hibachi chef in ${cityName}. $55/adult · full setup & cleanup · free quote. Hibachi Connect serves all ${stateName}.`\n        }\n    };\n}\n// ── JSON-LD Schema generators ────────────────────────────────────────────────\nfunction generateLocalBusinessSchema(cityData) {\n    const { cityName, stateName, stateSlug } = cityData;\n    const slug = cityName.toLowerCase().replace(/[^a-z0-9]+/g, \"-\");\n    const pageUrl = `https://hibachiconnect.com/locations/${stateSlug}/${slug}`;\n    return {\n        \"@context\": \"https://schema.org\",\n        \"@type\": [\n            \"ProfessionalService\",\n            \"FoodEstablishment\"\n        ],\n        name: \"Hibachi Connect\",\n        url: pageUrl,\n        telephone: \"+16027672965\",\n        email: \"info@hibachiconnect.com\",\n        image: \"https://hibachiconnect.com/brand/logo.png\",\n        logo: \"https://hibachiconnect.com/brand/logo.png\",\n        description: `Private hibachi chef service in ${cityName}, ${stateName}. We bring a live teppanyaki grill, fresh ingredients, and full entertainment to your home or event venue. Starting at $55/adult.`,\n        areaServed: {\n            \"@type\": \"City\",\n            name: cityName,\n            containedInPlace: {\n                \"@type\": \"State\",\n                name: stateName\n            }\n        },\n        address: {\n            \"@type\": \"PostalAddress\",\n            addressLocality: cityName,\n            addressRegion: stateName,\n            addressCountry: \"US\"\n        },\n        priceRange: \"$$\",\n        servesCuisine: [\n            \"Japanese\",\n            \"Hibachi\",\n            \"Teppanyaki\"\n        ],\n        currenciesAccepted: \"USD\",\n        paymentAccepted: \"Cash, Credit Card, Venmo, Zelle\",\n        aggregateRating: {\n            \"@type\": \"AggregateRating\",\n            ratingValue: \"5.0\",\n            reviewCount: \"200\",\n            bestRating: \"5\",\n            worstRating: \"1\"\n        },\n        hasOfferCatalog: {\n            \"@type\": \"OfferCatalog\",\n            name: \"Private Hibachi Chef Packages\",\n            itemListElement: [\n                {\n                    \"@type\": \"Offer\",\n                    name: \"Standard Hibachi Package\",\n                    price: \"55\",\n                    priceCurrency: \"USD\",\n                    description: \"Per adult — choose 2 proteins, fried rice, grilled vegetables, salad, miso soup, yum yum and ginger sauce, full setup and cleanup.\",\n                    availability: \"https://schema.org/InStock\"\n                },\n                {\n                    \"@type\": \"Offer\",\n                    name: \"Premium Hibachi Package\",\n                    price: \"65\",\n                    priceCurrency: \"USD\",\n                    description: \"Per adult — choose 3 proteins, fried rice and noodles, grilled vegetables, salad, miso soup, edamame, all sauces, priority booking.\",\n                    availability: \"https://schema.org/InStock\"\n                },\n                {\n                    \"@type\": \"Offer\",\n                    name: \"Elite / Corporate Package\",\n                    price: \"0\",\n                    priceCurrency: \"USD\",\n                    description: \"Custom quote — unlimited proteins, multiple chef stations, filet mignon and lobster tail, dedicated event coordinator, 200+ guest capacity.\",\n                    availability: \"https://schema.org/InStock\"\n                }\n            ]\n        },\n        sameAs: [\n            \"https://www.instagram.com/hibachiconnect\",\n            \"https://www.facebook.com/hibachiconnect\"\n        ]\n    };\n}\nfunction generateFAQSchema(faqSet) {\n    return {\n        \"@context\": \"https://schema.org\",\n        \"@type\": \"FAQPage\",\n        mainEntity: faqSet.map((faq)=>({\n                \"@type\": \"Question\",\n                name: faq.q,\n                acceptedAnswer: {\n                    \"@type\": \"Answer\",\n                    text: faq.a\n                }\n            }))\n    };\n}\nfunction generateBreadcrumbSchema(cityName, stateName, stateSlug) {\n    const citySlug = cityName.toLowerCase().replace(/[^a-z0-9]+/g, \"-\");\n    return {\n        \"@context\": \"https://schema.org\",\n        \"@type\": \"BreadcrumbList\",\n        itemListElement: [\n            {\n                \"@type\": \"ListItem\",\n                position: 1,\n                name: \"Home\",\n                item: \"https://hibachiconnect.com\"\n            },\n            {\n                \"@type\": \"ListItem\",\n                position: 2,\n                name: \"Locations\",\n                item: \"https://hibachiconnect.com/locations\"\n            },\n            {\n                \"@type\": \"ListItem\",\n                position: 3,\n                name: stateName,\n                item: `https://hibachiconnect.com/locations/${stateSlug}`\n            },\n            {\n                \"@type\": \"ListItem\",\n                position: 4,\n                name: cityName,\n                item: `https://hibachiconnect.com/locations/${stateSlug}/${citySlug}`\n            }\n        ]\n    };\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./lib/cityData.js\n");

